// Exit codes for ddx try terminal outcomes. These are specific to ddx try
// and intentionally do not reuse the generic ExitCode* constants because
// the bead-execution outcome vocabulary is distinct from generic CLI errors.
const (
	tryExitSuccess         = 0 // success or already_satisfied
	tryExitPreservedOrNone = 1 // preserved_for_review or no_changes
	tryExitFailed          = 2 // execution_failed or any other terminal non-success
)

// newTryCommand creates the top-level "ddx try <bead-id>" command.
// It targets a single specific bead through the full production execution
// machinery (claim → execute → land → review), unlike "ddx work" which drains
// the queue by picker priority and cannot force a specific bead.
func (f *CommandFactory) newTryCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:          "try <bead-id>",
		Short:        "Execute a specific bead through the production machinery",
		SilenceUsage: true,
		Long: `try executes a single named bead through the full production
execution machinery: claim → execute → land → review.

Unlike "ddx work" which drains the queue by picker priority, "ddx try"
targets a specific bead ID. This is useful for:
  - Operator-driven debugging when a bead misbehaves under autonomous drain
  - Deterministic queue ordering during refactor execution (dispatch each child
    in dep order with an explicit ID)
  - Path-comparison studies that need to execute one fixture bead at a time

Pre-flight checks (run before any claim is issued):
  - bead not found → non-zero exit with "bead not found: <id>"
  - bead not claimable (status=closed, cancelled, etc.) → non-zero exit
  - bead has unmet dependencies → non-zero exit listing the blockers

Review is on by default. --no-review is a break-glass override and
requires --no-review-i-know-what-im-doing. A bead label of review:skip
is only honored when it also carries a sibling review:skip-reason:*
label; otherwise the label is ignored.

Flag plumbing is identical to "ddx work": --harness, --model, --provider,
--profile, --effort are forwarded to the agent as opaque passthrough
constraints. DDx does not validate or branch on their string values.

Exit codes:
  0  success or already_satisfied
  1  preserved_for_review or no_changes
  2  execution_failed or any other terminal non-success
`,
		Example: `  # Execute a specific bead
  ddx try ddx-abc12345

  # Execute with an explicit harness and model
  ddx try ddx-abc12345 --harness codex --model gpt-5.4-mini

  # Execute without the post-merge review step (break-glass only)
  ddx try ddx-abc12345 --no-review --no-review-i-know-what-im-doing`,
		Args: cobra.ExactArgs(1),
		RunE: f.runTry,
	}

	// Routing knobs — identical to "ddx work" passthrough surface.
	cmd.Flags().String("project", "", "Target project root path or name (default: CWD git root). Env: DDX_PROJECT_ROOT")
	cmd.Flags().String("from", "", "Base git revision to start from (default: HEAD)")
	cmd.Flags().String("harness", "", "Agent harness constraint (passthrough; ddx try does not validate)")
	cmd.Flags().String("model", "", "Model constraint (passthrough; ddx try does not validate)")
	cmd.Flags().String("profile", "", "Routing profile: default, cheap, fast, or smart (empty = unconstrained; let the agent service choose)")
	cmd.Flags().String("provider", "", "Provider constraint (passthrough; ddx try does not validate)")
	cmd.Flags().String("effort", "", "Effort level")
	cmd.Flags().Bool("no-review", false, "Skip post-merge review (break-glass: requires --no-review-i-know-what-im-doing)")
	cmd.Flags().Bool("no-review-i-know-what-im-doing", false, "Break-glass acknowledgement required when using --no-review")
	cmd.Flags().String("review-harness", "", "Harness for the post-merge reviewer (default: same as implementation harness)")
	cmd.Flags().String("review-model", "", "Model override for the post-merge reviewer (default: smart powerClass)")
	cmd.Flags().Duration("preclaim-timeout", workguard.DefaultPreClaimTimeout, "Pre-claim readiness timeout for preflight/readiness hooks")
	cmd.Flags().Duration("request-timeout", 0, "Per-request provider wall-clock timeout; overrides project config and model-class defaults")
	cmd.Flags().Int("min-power", 0, "Minimum model power required (0 = unconstrained)")
	cmd.Flags().Int("max-power", 0, "Maximum model power allowed (0 = unconstrained)")

	return cmd
}

// runTry is the RunE for "ddx try <bead-id>".
func (f *CommandFactory) runTry(cmd *cobra.Command, args []string) error {
	if err := f.checkLifecycleMigrationGate(cmd); err != nil {
		return err
	}

	beadID := args[0]

	projectFlag, _ := cmd.Flags().GetString("project")
	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
	if err := f.failIfInstalledBinaryBehindSource(cmd, projectRoot, tryExitFailed); err != nil {
		return err
	}

	if _, err := newStartupHousekeepingRunner(projectRoot).Cleanup(cmd.Context()); err != nil {
		return err
	}

	// Preflight: warn once per process for degraded project-local skill layout.
	// Runs before claim/worktree setup so the operator sees the warning before
	// any bead state changes.
	preflightResult := checkProjectRuntimePreflight(projectRoot)
	f.preflightWarnOnce.Do(func() {
		emitPreflightWarning(cmd.ErrOrStderr(), preflightResult)
	})

	fromRev, _ := cmd.Flags().GetString("from")
	harness, _ := cmd.Flags().GetString("harness")
	model, _ := cmd.Flags().GetString("model")
	profile, _ := cmd.Flags().GetString("profile")
	provider, _ := cmd.Flags().GetString("provider")
	effort, _ := cmd.Flags().GetString("effort")
	noReview, _ := cmd.Flags().GetBool("no-review")
	noReviewAck, _ := cmd.Flags().GetBool("no-review-i-know-what-im-doing")
	reviewHarness, _ := cmd.Flags().GetString("review-harness")
	reviewModel, _ := cmd.Flags().GetString("review-model")
	requestTimeout, _ := cmd.Flags().GetDuration("request-timeout")
	minPower, _ := cmd.Flags().GetInt("min-power")
	maxPower, _ := cmd.Flags().GetInt("max-power")

	if noReview && !noReviewAck {
		return fmt.Errorf("--no-review requires --no-review-i-know-what-im-doing (break-glass acknowledgement)")
	}

	if f.tryExecutorOverride == nil {
		if err := agent.ValidateForExecuteLoopViaService(cmd.Context(), f.WorkingDir, harness, model, provider); err != nil {
			return err
		}
	}

	store := bead.NewStore(ddxroot.JoinProject(projectRoot))

	// Pre-flight: look up the bead.
	target, err := store.Get(context.Background(), beadID)
	if err != nil {
		fmt.Fprintf(cmd.ErrOrStderr(), "bead not found: %s\n", beadID)
		return &ExitError{Code: tryExitFailed, Message: ""}
	}

	// Pre-flight: verify the bead is in a claimable state.
	// Claimable = open, or stale in_progress (the loop handles stale reclaim).
	switch target.Status {
	case bead.StatusOpen, bead.StatusInProgress:
		// allowed — loop's Claim() handles stale-heartbeat reclaim
	default:
		fmt.Fprintf(cmd.ErrOrStderr(), "bead is not claimable (status=%s)\n", target.Status)
		return &ExitError{Code: tryExitFailed, Message: ""}
	}

	// Pre-flight: check for unmet dependencies.
	if unmet := unmetDeps(store, target); len(unmet) > 0 {
		fmt.Fprintf(cmd.ErrOrStderr(), "bead has unmet dependencies: %s\n", strings.Join(unmet, ", "))
		return &ExitError{Code: tryExitFailed, Message: ""}
	}

	// Wrap the real store so that ReadyExecution() returns only the target bead.
	// All other operations pass through to the underlying store unchanged.
	forcedStore := &singleBeadStore{Store: store, target: *target}

	// Set up progress logging (same as runAgentExecuteLoopImpl).
	loopSessionID := fmt.Sprintf("agent-loop-%d", time.Now().UnixNano())
	loopLogDir := filepath.Join(projectRoot, agent.DefaultLogDir)
	_ = os.MkdirAll(loopLogDir, 0o755)
	loopLogPath := filepath.Join(loopLogDir, loopSessionID+".jsonl")
	var loopSink io.Writer
	if lf, openErr := os.OpenFile(loopLogPath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644); openErr == nil {
		loopSink = lf
		defer lf.Close() //nolint:errcheck
	}

	// Worker-probe (best-effort server mirror; non-blocking).
	probeIdent := workerprobe.Identity{
		ProjectRoot:  projectRoot,
		Harness:      harness,
		Model:        model,
		ExecutorPID:  os.Getpid(),
		ExecutorHost: hostnameOrEmpty(),
		StartedAt:    time.Now().UTC(),
	}
	probe := workerprobe.New(probeIdent, workerprobe.Config{
		AddrFunc: serverpkg.ReadServerAddr,
	})
	probeCtx, probeCancel := context.WithCancel(context.Background())
	probe.Start(probeCtx)
	defer func() {
		probeCancel()
		probe.Stop()
	}()
	if loopSink != nil {
		loopSink = workerprobe.TeeJSONL(loopSink, probe)
	} else {
		loopSink = workerprobe.TeeJSONL(io.Discard, probe)
	}

	if err := s.SetLifecycleStatus(id, StatusClosed, LifecycleTransitionOptions{
		ManualClose: true,
		Reason:      "manual close",
		Source:      "Store.Close",
	}); err != nil {
		return err
	}
	if err := s.externalizeEvents(id); err != nil {
		return err
	}
	// Emit accuracy override when operator closes a BLOCK-reviewed bead.
	// AppendEvent handles sidecar append for already-externalized events.
	if verdictWas == "BLOCK" {
		_ = s.AppendEvent(id, BeadEvent{
			Kind:      "review-accuracy-override",
			Summary:   "BLOCK verdict contradicted by operator close",
			Body:      "verdict_was=BLOCK\noperator_action=close\nreason=manual close",
			Source:    "Store.Close",
			CreatedAt: time.Now().UTC(),
		})
	}
	_ = s.RemoveClaimHeartbeat(id)
	s.maybeOpportunisticMaintenance()
	return nil
}

// externalizeEvents moves a bead's inline events into its sidecar attachment
// under a fresh lock. Safe to call repeatedly — no-op when there are no
// inline events (already externalized, or none recorded).
func (s *Store) externalizeEvents(id string) error {
	if s.axonGraphQLActive() {
		return nil
	}
	return s.WithLock(func() error {
		beads, _, err := s.readAllLatestRaw()
		if err != nil {
			return err
		}
		for i := range beads {
			if beads[i].ID != id {
				continue
			}
			if err := s.externalizeEventsInPlace(&beads[i]); err != nil {
				return err
			}
			return s.WriteAll(beads)
		}
		return nil
	})
}

// ErrClosureGateRejected indicates a close was refused because the bead does
// not carry the evidence required for an automated closure: a terminal
// verdict event (review APPROVE with non-empty rationale, or an explicit
// review-skipped / manual-close marker) AND an execution-evidence marker
// (closing_commit_sha, session_id, or an execute-bead success event in the
// events history).
//
// Automated work paths (execute-bead + reviewer) always go through
// CloseWithEvidence. The plain Store.Close remains as the manual
// administration escape hatch — it bypasses the gate by design (ddx-e30e60a9
// acceptance §1).
var ErrClosureGateRejected = fmt.Errorf("closure gate: insufficient evidence")

// ClosureGate inspects a bead and returns nil iff the close is safe. It
// rejects only the specific shapes that caused the 2026-04-18/20
// review-malfunction incidents:
//
//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
//     closing_commit_sha. Rejected by the execution-evidence check —
//     closing_commit_sha must be non-empty OR at least one event must exist.
//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
//     body is empty. Rejected — APPROVE with no rationale is exactly the
//     parse-mis-extract shape the reviewer bug produced.
//
// Beads without a review step (--no-review, no Reviewer configured, already-
// satisfied paths) pass the gate as long as they carry execution evidence.
// This keeps the surface small: the gate catches known-bad shapes, not every
// conceivable edge case. Additional invariants belong in future dedicated
// beads so the rejection reason stays auditable.
func ClosureGate(b *Bead) error {
	if b == nil {
		return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
	}
	hasClosingCommit := false
	if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
		hasClosingCommit = true
	}
	events := decodeBeadEvents(b.Extra["events"])
	// Externalized events still count as evidence for the gate. We only need
	// to know whether *some* event history exists, not iterate it; the
	// gate's APPROVE-with-empty-rationale check below relies on inline events
	// (the verdict is recorded before externalization).
	hasAttachedEvents := hasEventsAttachment(b)
	// Reject the axon-c5cc071a shape: no events AND no closing commit.
	if len(events) == 0 && !hasAttachedEvents && !hasClosingCommit {
		return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
	}
	// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
	for _, e := range events {
		if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
			if strings.TrimSpace(e.Body) == "" {
				return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
			}
		}
	}
	return nil
}

// CloseWithEvidence sets a bead's status to closed and records agent session evidence.
// sessionID is the agent session that completed the work.
// commitSHA is the exact closing commit SHA when it is known.
//
// Enforces ClosureGate (ddx-e30e60a9): a bead cannot transition to closed
// via this path without a terminal verdict event plus execution evidence.
// Store.Close is the manual-administration escape hatch when the gate is
// inappropriate.
func (s *Store) CloseWithEvidence(id string, sessionID string, commitSHA string) error {
	if err := s.closeWithEvidence(id, sessionID, commitSHA); err != nil {
		return err
	}
	// Externalize events only when the gate actually transitioned the bead
	// to closed; rejected closes leave the bead open and inline.
	if b, err := s.Get(context.Background(), id); err == nil && b != nil && b.Status == StatusClosed {
		if err := s.externalizeEvents(id); err != nil {
			return err
		}
	}
	_ = s.RemoveClaimHeartbeat(id)
	s.maybeOpportunisticMaintenance()
	return nil
}

func (s *Store) closeWithEvidence(id string, sessionID string, commitSHA string) error {
	return s.updateBead(id, true, func(b *Bead) error {
		if b.Extra == nil {
			b.Extra = make(map[string]any)
		}
		if sessionID != "" {
			b.Extra["session_id"] = sessionID
		}
		if commitSHA != "" {
			b.Extra["closing_commit_sha"] = commitSHA
		}
		// ClosureGate guards the evidence-close path only; reconcile-close skips
		// it by design (TD-031 §5).
		if err := ClosureGate(b); err != nil {
			// Surface via bead notes so a later operator audit can see why the
			// close was refused; a single error path would be dropped by the
			// Update callback signature (no error return).
			appendClosureRejectNote(b, err)
			return nil
		}
		return transitionLifecycleInPlace(b, StatusClosed, LifecycleTransitionOptions{
			ManualClose: true,
			Reason:      "close with evidence",
			Source:      "Store.CloseWithEvidence",
		})
	})
}

func appendClosureRejectNote(b *Bead, err error) {
	stamp := time.Now().UTC().Format(time.RFC3339)
	note := fmt.Sprintf("[%s] closure rejected: %v", stamp, err)
	if b.Notes == "" {
		b.Notes = note
		return
	}
	b.Notes = b.Notes + "\n" + note
}

// AppendNotes appends operator-facing notes to an existing bead.
func (s *Store) AppendNotes(id string, appendNotes string) error {
	appendNotes = strings.TrimSpace(appendNotes)
	if appendNotes == "" {
		return nil
	}
	return s.Update(context.Background(), id, func(b *Bead) {
		if b.Notes != "" {
			b.Notes = b.Notes + "\n\n" + appendNotes
			return
		}
		b.Notes = appendNotes
	})
}

// Reopen sets a bead's status back to open, clears claim fields, optionally
// appends notes, and records an immutable reopen event — all in one atomic
// lock acquisition.
func (s *Store) Reopen(id string, reason string, appendNotes string) error {
	now := time.Now().UTC()
	return s.WithLock(func() error {
		beads, _, err := s.readAllLatestRaw()
		if err != nil {
			return err
		}
		found := false
		for i := range beads {
			if beads[i].ID != id {
				continue
			}
			b := &beads[i]
			if err := transitionLifecycleInPlace(b, StatusOpen, LifecycleTransitionOptions{
				ManualReopen: true,
			}); err != nil {
				return err
			}
			b.Owner = ""
			b.UpdatedAt = now
			if b.Extra == nil {
				b.Extra = make(map[string]any)
			}
			// Clear claim fields
			for _, k := range ClaimMetadataExtraKeys {
				delete(b.Extra, k)
			}
			delete(b.Extra, ClaimHeartbeatExtraKey)
			// Append notes
			if appendNotes != "" {
				if b.Notes != "" {
					b.Notes = b.Notes + "\n\n" + appendNotes
				} else {
					b.Notes = appendNotes
				}
			}
			// Record reopen event. If events were externalized at close,
			// pull them back inline so the active row carries the full
			// history again and the attachment ref is dropped.
			if hasEventsAttachment(b) {
				if err := s.inlineEventsInPlace(b); err != nil {
					return err
				}
				_ = os.Remove(s.eventsAttachmentPath(b.ID))
			}
			var events []BeadEvent
			if raw, ok := b.Extra["events"]; ok {
				events = decodeBeadEvents(raw)
			}
			// Detect last review verdict before appending the reopen event so
			// we can identify APPROVE verdicts contradicted by the operator.
			verdictWas := lastReviewVerdictFromEvents(events)
			evt := BeadEvent{
				Kind:      "reopen",
				CreatedAt: now,
			}
			if reason != "" {
				evt.Summary = reason
			}
			events = append(events, evt)
			// Emit accuracy override when operator reopens an APPROVE-reviewed
			// bead (potential false-negative — reviewer approved fake work).
			if verdictWas == "APPROVE" {
				body := "verdict_was=APPROVE\noperator_action=reopen"
				if reason != "" {
					body += "\nreason=" + reason
				}
				events = append(events, BeadEvent{
					Kind:      "review-accuracy-override",
					Summary:   "APPROVE verdict contradicted by operator reopen",
					Body:      body,
					Source:    "Store.Reopen",
					CreatedAt: now,
				})
			}
			encoded := make([]map[string]any, 0, len(events))
			for _, e := range events {
				encoded = append(encoded, map[string]any{
					"kind":       e.Kind,
					"summary":    e.Summary,
					"body":       e.Body,
					"actor":      e.Actor,
					"created_at": e.CreatedAt,
					"source":     e.Source,
				})
			}
			b.Extra["events"] = encoded
			if err := s.validateBead(b); err != nil {
				return err
			}
			if err := s.runHook("validate-bead-update", b); err != nil {
				return err
			}
			found = true
			break
		}
		if !found {
			return fmt.Errorf("bead: not found: %s", id)
		}
		if err := s.WriteAll(beads); err != nil {
			return err
		}
		return s.RemoveClaimHeartbeat(id)
	})
}

