// TestTryProseFindings_FedBackBeforeFinalization: the prose hook runs before
// the bead is closed so findings land in the editable attempt's evidence
// history. We verify this by capturing the bead status when the hook fires —
// it must still be in_progress, not closed.
func TestTryProseFindings_FedBackBeforeFinalization(t *testing.T) {
	env := NewTestEnvironment(t)
	store := newTryProseTestBead(t, env, "timing-bead-001")

	var mu sync.Mutex
	var statusAtHook string
	var hookFired bool

	factory := NewCommandFactory(env.Dir)
	factory.AgentRunnerOverride = &tryHookRunnerStub{t: t}
	factory.tryExecutorOverride = agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		return newTryProseStubReport(beadID), nil
	})
	factory.proseEvidenceHookOverride = func(ctx context.Context, beadID string, report agent.ExecuteBeadReport) error {
		mu.Lock()
		defer mu.Unlock()
		hookFired = true
		if b, err := store.Get(beadID); err == nil {
			statusAtHook = b.Status
		}
		return nil
	}

	root := factory.NewRootCommand()
	out, err := executeCommand(root, "try", "timing-bead-001", "--no-review", "--no-review-i-know-what-im-doing")
	require.NoError(t, err, "ddx try must succeed: %s", out)

	mu.Lock()
	defer mu.Unlock()
	require.True(t, hookFired, "prose hook must run for a successful docs-changing attempt")
	assert.Equal(t, bead.StatusInProgress, statusAtHook,
		"prose hook must run before CloseWithEvidence; bead status at hook time must still be in_progress, not closed")

	// Sanity: after the loop completes the bead must be closed.
	b, err := store.Get("timing-bead-001")
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, b.Status)
}

package bead

import (
	"crypto/sha1"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

const claimLivenessNamespace = "ddx-claim-heartbeats"

type ClaimLeaseRecord struct {
	BeadID    string    `json:"bead_id"`
	Owner     string    `json:"owner,omitempty"`
	Session   string    `json:"session,omitempty"`
	Worktree  string    `json:"worktree,omitempty"`
	Machine   string    `json:"machine,omitempty"`
	StartedAt time.Time `json:"started_at,omitempty"`
	UpdatedAt time.Time `json:"updated_at"`
	PID       int       `json:"pid,omitempty"`
}

func claimLivenessPath(ddxDir, id string) string {
	root := canonicalClaimRoot(ddxDir)
	sum := sha1.Sum([]byte(root))
	return filepath.Join(os.TempDir(), claimLivenessNamespace, hex.EncodeToString(sum[:]), id+".json")
}

func canonicalClaimRoot(ddxDir string) string {
	root := filepath.Clean(filepath.Dir(ddxDir))
	if abs, err := filepath.Abs(root); err == nil {
		root = abs
	}
	if real, err := filepath.EvalSymlinks(root); err == nil {
		root = real
	}
	return filepath.Clean(root)
}

func writeAtomicClaimFile(path string, data []byte) error {
	dir := filepath.Dir(path)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("bead: mkdir claim liveness dir: %w", err)
	}
	tmp, err := os.CreateTemp(dir, filepath.Base(path)+".tmp-*")
	if err != nil {
		return fmt.Errorf("bead: create claim liveness tmp: %w", err)
	}
	tmpName := tmp.Name()
	defer func() {
		_ = tmp.Close()
		_ = os.Remove(tmpName)
	}()
	if _, err := tmp.Write(data); err != nil {
		return fmt.Errorf("bead: write claim liveness tmp: %w", err)
	}
	if err := tmp.Close(); err != nil {
		return fmt.Errorf("bead: close claim liveness tmp: %w", err)
	}
	if err := os.Rename(tmpName, path); err != nil {
		return fmt.Errorf("bead: publish claim liveness: %w", err)
	}
	return nil
}

func (s *Store) writeClaimHeartbeat(rec ClaimLeaseRecord) error {
	data, err := json.Marshal(rec)
	if err != nil {
		return fmt.Errorf("bead: marshal claim liveness: %w", err)
	}
	data = append(data, '\n')
	return writeAtomicClaimFile(claimLivenessPath(s.Dir, rec.BeadID), data)
}

func (s *Store) readClaimHeartbeat(id string) (ClaimLeaseRecord, bool, error) {
	data, err := os.ReadFile(claimLivenessPath(s.Dir, id))
	if os.IsNotExist(err) {
		return ClaimLeaseRecord{}, false, nil
	}
	if err != nil {
		return ClaimLeaseRecord{}, false, fmt.Errorf("bead: read claim liveness: %w", err)
	}
	var rec ClaimLeaseRecord
	if err := json.Unmarshal(data, &rec); err != nil {
		return ClaimLeaseRecord{}, true, fmt.Errorf("bead: parse claim liveness: %w", err)
	}
	return rec, true, nil
}

func (s *Store) upsertClaimHeartbeat(id string, mutate func(*ClaimLeaseRecord)) error {
	rec, found, err := s.readClaimHeartbeat(id)
	if err != nil {
		return err
	}
	now := time.Now().UTC()
	if !found {
		rec = ClaimLeaseRecord{
			BeadID:    id,
			StartedAt: now,
		}
	}
	if rec.BeadID == "" {
		rec.BeadID = id
	}
	if rec.StartedAt.IsZero() {
		rec.StartedAt = now
	}
	rec.UpdatedAt = now
	if rec.PID == 0 {
		rec.PID = os.Getpid()
	}
	if mutate != nil {
		mutate(&rec)
	}
	data, err := json.Marshal(rec)
	if err != nil {
		return fmt.Errorf("bead: marshal claim liveness: %w", err)
	}
	data = append(data, '\n')
	return writeAtomicClaimFile(claimLivenessPath(s.Dir, id), data)
}

func (s *Store) TouchClaimHeartbeat(id string) error {
	return s.upsertClaimHeartbeat(id, nil)
}

func (s *Store) RemoveClaimHeartbeat(id string) error {
	err := os.Remove(claimLivenessPath(s.Dir, id))
	if err == nil || os.IsNotExist(err) {
		return nil
	}
	return fmt.Errorf("bead: remove claim liveness: %w", err)
}

func (s *Store) ClaimHeartbeatFresh(id string) (bool, bool, error) {
	rec, found, err := s.readClaimHeartbeat(id)
	if err != nil {
		return false, false, err
	}
	if !found {
		return false, false, nil
	}
	if rec.UpdatedAt.IsZero() {
		return false, true, nil
	}
	return time.Since(rec.UpdatedAt) <= HeartbeatTTL, true, nil
}

// ClaimLease returns the external worker/manual claim sidecar for id when one
// exists. The record is the operator-facing live claim surface for workers; the
// tracker still carries any explicit manual lifecycle status change.
func (s *Store) ClaimLease(id string) (ClaimLeaseRecord, bool, error) {
	return s.readClaimHeartbeat(id)
}

// is considered stalled and will be reclaimed atomically.
func (s *Store) Claim(id, assignee string) error {
	machine, _ := os.Hostname()
	if envID := os.Getenv("DDX_MACHINE_ID"); envID != "" {
		machine = envID
	}
	return s.WithLock(func() error {
		beads, _, err := s.readAllLatestRaw()
		if err != nil {
			return err
		}
		for i := range beads {
			if beads[i].ID != id {
				continue
			}
			switch beads[i].Status {
			case StatusOpen:
				// normal claim path
			case StatusInProgress:
				if !claimLeaseIsStale(s, beads[i].Extra, id) {
					return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
				}
				// stalled claim — reclaim atomically below
			default:
				return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
			}
			if err := transitionLifecycleInPlace(&beads[i], StatusInProgress, LifecycleTransitionOptions{
				Reason: "claim",
				Actor:  assignee,
				Source: "Store.Claim",
			}); err != nil {
				return err
			}
			now := time.Now().UTC()
			beads[i].Owner = assignee
			beads[i].UpdatedAt = now
			if beads[i].Extra == nil {
				beads[i].Extra = make(map[string]any)
			}
			// Compatibility cleanup only: worker/live claim metadata now lives in
			// the external lease sidecar rather than the tracked row.
			for _, key := range ClaimMetadataExtraKeys {
				delete(beads[i].Extra, key)
			}
			delete(beads[i].Extra, ClaimHeartbeatExtraKey)
			if err := s.validateBead(&beads[i]); err != nil {
				return err
			}
			if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
				return err
			}
			if err := s.WriteAll(beads); err != nil {
				return err
			}
			return s.writeClaimHeartbeat(ClaimLeaseRecord{
				BeadID:    id,
				Owner:     assignee,
				Machine:   machine,
				StartedAt: now,
				UpdatedAt: now,
				PID:       os.Getpid(),
			})
		}
		return fmt.Errorf("bead: not found: %s", id)
	})
}

// ClaimWithOptions acquires or refreshes the external worker-claim lease
// without mutating the tracked bead row. session and worktree are optional;
// machine is derived from os.Hostname(). A stalled open/in_progress bead
// (external lease older than HeartbeatTTL) is reclaimed atomically under the
// store's lock.
func (s *Store) ClaimWithOptions(id, assignee, session, worktree string) error {
	machine, _ := os.Hostname()
	if envID := os.Getenv("DDX_MACHINE_ID"); envID != "" {
		machine = envID
	}
	return s.WithLock(func() error {
		beads, _, err := s.readAllLatestRaw()
		if err != nil {
			return err
		}
		for i := range beads {
			if beads[i].ID != id {
				continue
			}
			switch beads[i].Status {
			case StatusOpen:
				// worker lease path
			case StatusInProgress:
				if !claimLeaseIsStale(s, beads[i].Extra, id) {
					return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
				}
				// stalled claim — reclaim atomically below
			default:
				return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
			}
			now := time.Now().UTC()
			return s.writeClaimHeartbeat(ClaimLeaseRecord{
				BeadID:    id,
				Owner:     assignee,
				Session:   session,
				Worktree:  worktree,
				Machine:   machine,
				StartedAt: now,
				UpdatedAt: now,
				PID:       os.Getpid(),
			})
		}
		return fmt.Errorf("bead: not found: %s", id)
	})
}

// Heartbeat refreshes the external claim liveness lease on a claimed bead.
// Returns an error if the bead is no longer in_progress (e.g., reclaimed by
// another worker), allowing the caller to stop its heartbeat loop.
//
// Deprecated: use TouchClaimHeartbeat.
func (s *Store) Heartbeat(id string) error {
	if err := s.WithLock(func() error {
		beads, _, err := s.readAllLatestRaw()
		if err != nil {
			return err
		}
		for _, b := range beads {
			if b.ID != id {
				continue
			}
			if b.Status != StatusInProgress {
				return fmt.Errorf("bead: cannot heartbeat %s from status %s", id, b.Status)
			}
			return s.TouchClaimHeartbeat(id)
		}
		return fmt.Errorf("bead: not found: %s", id)
	}); err != nil {
		return err
	}
	return nil
}

// claimLeaseIsStale returns true if the external claim lease is absent or
// older than HeartbeatTTL. When no lease file exists, it falls back to the
// legacy tracker heartbeat field for compatibility with imported/stale rows.
func claimLeaseIsStale(s *Store, extra map[string]any, id string) bool {
	if s != nil {
		if fresh, found, err := s.ClaimHeartbeatFresh(id); err == nil {
			if found {
				return !fresh
			}
		} else {
			return heartbeatIsStale(extra)
		}
	}
	return heartbeatIsStale(extra)
}

// heartbeatIsStale returns true if the given bead's legacy Extra map has no
// heartbeat field or one older than HeartbeatTTL.
func heartbeatIsStale(extra map[string]any) bool {
	if extra == nil {
		return true
	}
	raw, ok := extra["work-heartbeat-at"]
	if !ok {
		return true
	}
	s, ok := raw.(string)
	if !ok || s == "" {
		return true
	}
	t, err := time.Parse(time.RFC3339Nano, s)
	if err != nil {
		// Fall back to RFC3339 for compatibility with legacy entries written
		// before sub-second resolution. RFC3339Nano is the current canonical
		// format used by both ClaimWithOptions and Heartbeat write sites.
		t, err = time.Parse(time.RFC3339, s)
		if err != nil {
			return true
		}
	}
	return time.Since(t) > HeartbeatTTL
}

// Unclaim clears claim metadata. Only reverts status to open if the bead
// is currently in_progress — a closed bead stays closed.
func (s *Store) Unclaim(id string) error {

		Use:   "show <id>",
